def search_texts_for(term, data, field_candidates):
    # return list of entries containing normalized term substring
    term_norm = normalize_arabic(term)
    res = []
    for rec in data:
        for field in field_candidates:
            text = rec.get(field)
            if text:
                if normalize_arabic(text).find(term_norm) != -1:
                    res.append((text, rec))
                    break
    return res

